const startDay = flow.get('holidayStartDay') || 25;
const endMonth = flow.get('holidayEndMonth') || 1;
const endDay = flow.get('holidayEndDay') || 6;

let isHoliday;
if (startMonth <= endMonth) {
    // Range within same year (e.g., Mar 1 – Dec 31)
    isHoliday = (month > startMonth || (month === startMonth && day >= startDay)) &&
                (month < endMonth || (month === endMonth && day <= endDay));
} else {
    // Range wraps around year end (e.g., Nov 25 – Jan 6)
    isHoliday = (month > startMonth || (month === startMonth && day >= startDay)) ||
                (month < endMonth || (month === endMonth && day <= endDay));
}

msg.isHoliday = isHoliday;
