    label: eventData.label,
    confidence: eventData.top_score,
    timestamp: Date.now(),
    zones: eventData.entered_zones || [],
    eventType: eventType
};

node.log(`Processing ${eventData.label} on ${eventData.camera} (${Math.round(eventData.top_score * 100)}% confidence)`);
return msg;

// Consolidate detections across labels (person + dog) into one group if close in time
const now = Date.now();
const entry = {
    camera: msg.eventData.camera,
    label: msg.eventData.label,           // 'person' or 'dog'
    eventData: msg.eventData,
    timestamp: now
};

// Tunables
const groupingWindow = 2000;   // 2s to collect "simultaneous" detections
const debounceWindow = 30000;  // 30s to avoid spamming consolidated alerts

// We now use ONE group for any qualifying labels/cameras
const GROUP_KEY = "group_any";
let group = context.get(GROUP_KEY);

// Helper to finalize and send the group
function finalizeAndSend(g) {
    if (!g || !g.entries || g.entries.length === 0) return;

    // Build unique labels in the group (e.g., ['person', 'dog'])
    const uniqueLabels = [...new Set(g.entries.map(e => e.label))];

    // Build cameras array to match downstream expectations
    const cameras = g.entries.map(e => ({
        camera: e.camera,
        eventData: e.eventData,
        timestamp: e.timestamp
    }));

    const outMsg = {
        detectionGroup: {
            labels: uniqueLabels,      // <-- array of labels now
            cameras,
            count: cameras.length
        }
    };

    node.send(outMsg);
    context.set("last_any", Date.now());
    node.log(`Processing consolidated group [${uniqueLabels.join(" + ")}] with ${cameras.length} event(s)`);
}

const lastAny = context.get("last_any") || 0;

// Start a new group if none exists or expired
if (!group || (now - group.firstDetection) > groupingWindow) {
    // Debounce globally (covers both single and combined cases)
    if (now - lastAny < debounceWindow) {
        node.log(`Debouncing consolidated notification (${now - lastAny}ms ago)`);
        return null;
    }

    // Start a fresh group
    group = {
        firstDetection: now,
        entries: [entry],
        timerId: null
    };
    context.set(GROUP_KEY, group);

    // Single timer to close the window and emit ONE message
    group.timerId = setTimeout(() => {
        const latest = context.get(GROUP_KEY);
        if (latest && latest.firstDetection === now) {
            finalizeAndSend(latest);
            // Clear group after sending
            context.set(GROUP_KEY, null);
        }
    }, groupingWindow + 100);

    return null;
}

// If we're still inside the grouping window, just append
group.entries.push(entry);
context.set(GROUP_KEY, group);
node.log(`Added ${entry.camera} (${entry.label}) to consolidated group (${group.entries.length} events)`);

