messageText += `\n⏰ ${timeStr}`;

// Output: same logic for photo count
const chatIds = ["321474212", "247971390"];
const out = [];

if (snapshots.length === 1) {
    chatIds.forEach(chatId => {
        const m = RED.util.cloneMessage(msg);
        m.payload = {
            chatId,
            type: "photo",
            content: snapshots[0].image,
            caption: messageText
        };
        out.push(m);
    });
} else if (snapshots.length === 2) {
    chatIds.forEach(chatId => {
        let m1 = RED.util.cloneMessage(msg);
        m1.payload = {
            chatId,
            type: "photo",
            content: snapshots[0].image,
            caption: cameraNames[0]
        };
        out.push(m1);

        let m2 = RED.util.cloneMessage(msg);
        m2.payload = {
            chatId,
            type: "photo",
            content: snapshots[1].image,
            caption: messageText
        };
        out.push(m2);
    });
} else {
    chatIds.forEach(chatId => {
        const m = RED.util.cloneMessage(msg);
        m.payload = {
            chatId,
            type: "photo",
            content: snapshots[0].image,
