// Prepare Snapshot Requests (one snapshot per camera)
const group = msg.detectionGroup;

if (!group || !group.cameras || group.cameras.length === 0) {
    node.error('No cameras in detection group');
    return null;
}

// Support both shapes: group.labels (array) or group.label (string)
const labels = Array.isArray(group.labels)
    ? group.labels
    : (group.label ? [group.label] : []);
const labelText = labels.length ? labels.join(" + ") : "unknown";

// --- NEW: collapse multiple detections from the SAME camera into a single snapshot request ---
// Keep the entry with the highest confidence per camera (or the latest if equal)
const bestByCamera = {};
for (const entry of group.cameras) {
    const cam = entry.camera;
    const conf = entry.eventData?.confidence ?? 0;
    if (!bestByCamera[cam] || conf >= (bestByCamera[cam].eventData?.confidence ?? 0)) {
        bestByCamera[cam] = entry;
    }
}

// Build snapshot requests in a stable order: front_door first if present, then doorbell, then others
const preferredOrder = ["front_door", "doorbell"];
const deduped = Object.values(bestByCamera).sort((a, b) => {
    const ia = preferredOrder.indexOf(a.camera);
    const ib = preferredOrder.indexOf(b.camera);
    if (ia !== -1 && ib !== -1) return ia - ib;
    if (ia !== -1) return -1;
    if (ib !== -1) return 1;
    return a.camera.localeCompare(b.camera);
});

const snapshotRequests = deduped.map((cameraData, index) => ({
    url: `http://frigate:5000/api/events/${cameraData.eventData.id}/snapshot.jpg?quality=95&h=720`,
    camera: cameraData.camera,
    confidence: cameraData.eventData.confidence,
    zones: cameraData.eventData.zones,
    index,
    eventId: cameraData.eventData.id
}));

msg.snapshotRequests = snapshotRequests;
msg.snapshots = [];
msg.currentIndex = 0;
msg.detectionGroup = group;

node.log(`Preparing to fetch ${snapshotRequests.length} snapshot(s) for [${labelText}] from camera(s): ${deduped.map(d => d.camera).join(", ")}`);

if (snapshotRequests.length > 0) {
    msg.url = snapshotRequests[0].url;
    msg.method = "GET";
    msg.headers = { "Accept": "image/jpeg" };
    msg.currentRequest = snapshotRequests[0];
    return msg;
}

return null;

// Process the received snapshot
const imageBuffer = msg.payload;
const currentRequest = msg.currentRequest;
const snapshotRequests = msg.snapshotRequests;
const currentIndex = msg.currentIndex;

let valid = false;

// Validate the image
if (!imageBuffer || imageBuffer.length < 5000) {
    node.warn(`❌ Invalid image from ${currentRequest.camera}: ${imageBuffer ? imageBuffer.length : 0} bytes`);
} else if (imageBuffer[0] !== 0xFF || imageBuffer[1] !== 0xD8) {
    node.warn(`❌ Invalid JPEG header from ${currentRequest.camera}`);
} else {
    // Valid image
    msg.snapshots.push({
        camera: currentRequest.camera,
        confidence: currentRequest.confidence,
        zones: currentRequest.zones,
        image: imageBuffer,
        index: currentRequest.index
    });
    node.log(`✅ Collected snapshot ${currentIndex + 1}/${snapshotRequests.length} from ${currentRequest.camera}`);
    valid = true;
}

// Check if we have more snapshots to fetch
if (currentIndex + 1 < snapshotRequests.length) {
    // Prepare next request
    msg.currentIndex = currentIndex + 1;
    const nextRequest = snapshotRequests[msg.currentIndex];

    msg.url = nextRequest.url;
    msg.method = "GET";
    msg.headers = { "Accept": "image/jpeg" };
    msg.currentRequest = nextRequest;

    return [null, msg]; // Output 2 → HTTP request
} else {
    // All snapshots collected
    if (msg.snapshots.length === 0) {
        node.error(`⚠️ No valid snapshots collected for group "${msg.detectionGroup.label}". Sending event anyway.`);
        // Push a placeholder so downstream still has data
        msg.snapshots = [{
            camera: currentRequest.camera,
            confidence: currentRequest.confidence,
            zones: currentRequest.zones,
            image: null, // no image
            index: currentRequest.index
        }];
    }

    // Sort snapshots by original index
    msg.snapshots.sort((a, b) => a.index - b.index);

    node.log(`📸 Completed: ${msg.snapshots.length}/${snapshotRequests.length} snapshots collected`);

    // Clean up temporary properties
    delete msg.currentIndex;
    delete msg.currentRequest;
    delete msg.snapshotRequests;
    delete msg.url;
    delete msg.method;
    delete msg.headers;
    delete msg.statusCode;
    delete msg.responseUrl;
    delete msg.redirectList;
    delete msg.retry;

    // Continue to format message
    return [msg, null]; // Output 1 → format message
}

